#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int evidence_cmem_bitint_c23_boundary_1o5hai(size_t count, size_t width, size_t limit, size_t *bytes) {
  if (bytes == NULL || width == 0) return 0;
  if (count > limit / width) return 0;
  *bytes = count * width;
  return 1;
}

int main(void) {
  size_t bytes = 99;
  int rejected = evidence_cmem_bitint_c23_boundary_1o5hai((size_t)25, (size_t)8, (size_t)64, &bytes);
  int accepted = evidence_cmem_bitint_c23_boundary_1o5hai((size_t)5, (size_t)4, (size_t)64, &bytes);
  int invariant = !rejected && accepted && bytes == (size_t)20;
  printf("size bytes=%lu invariant=%d\n", (unsigned long)bytes, invariant);
  return invariant ? 0 : 1;
}
